    public Set<BuildingDTO> upsertBuildingsByVdmsId(String username, String vdms_id, Set<BuildingDTO> buildings, HttpServletRequest httpServletRequest) {
        String action;
        for (BuildingDTO building : buildings) {
            action = "UPDATE";
            if (building.getBuilding_id() == null) {
                building.setBuilding_id(Generators.timeBasedGenerator().generate().toString());
                action = "ADD";
            }
            this.upsertBuildingById(building, vdms_id, username, action, httpServletRequest);
            if (building.getFloors() != null) {
                Set<FloorDTO> floors = floorservice.upsertFloorsByBuildingId(username, vdms_id, building.getBuilding_id(), building.getFloors(), httpServletRequest);
                building.setFloors(floors);
            }
        }
        return buildings;
    }

    private void upsertBuildingById(BuildingDTO building, String vdms_id, String username, String action, HttpServletRequest httpServletRequest) {
        try {
            BigInteger timestamp = BigInteger.valueOf(System.currentTimeMillis());
            int rowsAffected = buildingRepository.upsertBuildingsByVdmsId(building.getBuilding_id(), building.getName(), vdms_id, building.getCode(), timestamp);
            if (rowsAffected > 0) {
                syncBuildingToADCServer(building);
            }
            if (action.equals("ADD")) {
                userActionLogService.addUserAction(username, "maps", action, "A Building with name : " + building.getName() + " and id: " + building.getBuilding_id() + " is added", "success", "building", building.getBuilding_id());
                log.info("endpoint: {},upsertBuildingById, description: A new building is added,  params: building: {}", httpServletRequest.getRequestURI(), building);
            } else {
                userActionLogService.addUserAction(username, "maps", action, "A Building with name : " + building.getName() + " and id: " + building.getBuilding_id() + " is updated", "success", "building", building.getBuilding_id());
                log.info("endpoint: {},upsertBuildingById, description: A building is updated, params: building: {}", httpServletRequest.getRequestURI(), building);
            }
        } catch (Exception e) {
            log.error("Error : ", e);
            if (action.equals("ADD")) {
                userActionLogService.addUserAction(username, "maps", action, " Unable to add building with name: " + building.getName() + " and id: " + building.getBuilding_id(), "failed", "building", building.getBuilding_id());
                log.error("Exception in ADD building, endpoint: {} ,  Error message : ", httpServletRequest.getRequestURI(), e);
            } else {
                userActionLogService.addUserAction(username, "maps", action, " Unable to update building with name: " + building.getName() + " and id: " + building.getBuilding_id(), "failed", "building", building.getBuilding_id());
                log.error("Exception in UPDATE building, endpoint: {} ,  Error message : ", httpServletRequest.getRequestURI(), e);
            }
        }
    }

    public BuildingDTO getBuildingByLocationId(String username, String vdms_id, String location_id) {
        FloorDTO floor = floorservice.getFloorByLocationId(location_id);
        if (floor != null) {
            BuildingDTO building = buildingRepository.getBuildingByFloorId(floor.getFloor_id());
            if (building != null) {
                Set<FloorDTO> floors = new HashSet<>();
                floors.add(floor);
                building.setFloors(floors);
            }
            return building;
        }
        return null;
    }

    public Set<BuildingDTO> getBuildingsByVdmsId(String vdms_id, String field, String field_id) {
        Set<BuildingDTO> buildings = buildingRepository.getBuildingsByVdmsId(vdms_id);
        List<String> building_ids = buildings.stream().map(BuildingDTO::getBuilding_id).collect(Collectors.toList());
        Set<RecordChecklistDTO> allRecordChecklist = recordChecklistService.getAllRecordChecklistByBuildings(Collections.singletonList("all"), Collections.singletonList("all"), building_ids);
        for (BuildingDTO buildingDTO : buildings) {
            if (field != null) {
                Map<String, Long> defaultCounts = new HashMap<>();
                defaultCounts.put("tagged", 0L);
                defaultCounts.put("inspection", 0L);
                defaultCounts.put("scheduled_services", 0L);
                defaultCounts.put("reactive_services", 0L);
                Map<String, Long> computedCounts = allRecordChecklist.stream().filter(recordChecklistDTO -> recordChecklistDTO.getBuilding_id().equals(buildingDTO.getBuilding_id())).collect(Collectors.groupingBy(record -> {
                    String type = record.getRecord_type();
                    boolean hasInspectionId = record.getInspection_record_id() != null;
                    if ((field.equals("all_task") || field.equals("tagged")) && "checklist".equals(type) && !hasInspectionId) return "tagged";
                    if ((field.equals("all_task") || field.equals("inspection")) && "checklist".equals(type) && hasInspectionId) return "inspection";
                    if ((field.equals("all_task") || field.equals("scheduled_services")) && "service".equals(type) && hasInspectionId) return "scheduled_services";
                    if ((field.equals("all_task") || field.equals("reactive_services")) && "service".equals(type) && !hasInspectionId) return "reactive_services";
                    return "unknown"; // Exclude unmatched records
                }, Collectors.counting()));
                defaultCounts.putAll(computedCounts);
                JSONObject counts = new JSONObject();
                if (field.equals("all_task") || field.equals("tagged")) {
                    JSONObject tagged_count = new JSONObject();
                    tagged_count.put("all_count", defaultCounts.get("tagged"));
                    counts.put("tagged_procedure", tagged_count);
                }
                if (field.equals("all_task") || field.equals("reactive_services")) {
                    JSONObject reactive_service_count = new JSONObject();
                    reactive_service_count.put("all_count", defaultCounts.get("reactive_services"));
                    counts.put("service_requests", reactive_service_count);
                }
                if (field.equals("all_task") || field.equals("scheduled_services")) {
                    JSONObject scheduled_service_count = new JSONObject();
                    scheduled_service_count.put("all_count", defaultCounts.get("scheduled_services"));
                    counts.put("service_checklist", scheduled_service_count);
                }
                if (field.equals("all_task") || field.equals("inspection")) {
                    JSONObject inspection_count = new JSONObject();
                    inspection_count.put("all_count", defaultCounts.get("inspection"));
                    counts.put("inspection_checklist", inspection_count);
                }
                buildingDTO.setCounts(counts);
            }
        }
//        System.out.println(bulidingCount);
//        for (BuildingDTO buildingDTO : buildings) {
//            if (field != null) {
//                buildingDTO.setCounts(recordChecklistService.getAllMapCounts(field, field_id, "all", "all", buildingDTO.getBuilding_id()));
//                buildingDTO.setCounts(bulidingCount.get(buildingDTO.getBuilding_id()));
//            }
//        }
        return buildings;
    }

    public void deleteBuildingsByIdsSync(String username, String vdmsid, Set<String> buildingIds) {
        log.info("deleteBuildingsByIds method called with buildingIds: {}", buildingIds);
        List<BuildingDTO> buildings = getBatchBuildingsByPagination(buildingIds);
        if (buildings == null || buildings.isEmpty()) {
            return;
        }
        log.info("Getting floors by building ids");
        List<FloorDTO> floors = floorservice.getFloorsByBuildingIds(buildingIds);
        log.info("Processing floor deletions for floors: {}", floors.size());
        floorservice.processFloorDeletions(username, vdmsid, floors);
        buildingRepository.deleteAllById(buildingIds);
    }

    public List<BuildingDTO> getBatchBuildingsByPagination(Set<String> buildingIds) {
        List<BuildingDTO> buildings = new ArrayList<>();
        int pageNo = 1;
        int pageSize = 500;
        while (true) {
            int offset = pageSize * (pageNo - 1);
            List<BuildingDTO> batchResults = buildingRepository.getBatchBuildingsByPagination(buildingIds, pageSize, offset);
            if (batchResults == null || batchResults.isEmpty()) {
                break;
            }
            buildings.addAll(batchResults);
            if (batchResults.size() < pageSize) {
                break;
            }
            pageNo++;
        }
        return buildings;
    }

    public void deleteBuildingsByIds(String username, String vdmsid, Set<String> building_ids, HttpServletRequest httpServletRequest) {
        for (String id : building_ids) {
            deleteBuildingById(username, vdmsid, id, httpServletRequest);
        }
    }

    private void deleteBuildingById(String username, String vdmsid, String building_id, HttpServletRequest httpServletRequest) {
        String endpoint = httpServletRequest != null ? httpServletRequest.getRequestURI() : "SOCKET CALL";
        Set<FloorDTO> floors = floorservice.getFloorsDetailsByBuildingId(building_id);
        List<FloorDTO> floorDetails = new ArrayList<>(floors);
        String data = webClientService.deleteFloorMapsByImageUrl(vdmsid, floorDetails);
        if (data != null) {
            floorservice.deleteFloorsByBuildingId(vdmsid, building_id, username, httpServletRequest);
            BuildingDTO buildingDTO = this.getBuildingDetailsByBuildingId(building_id);
            try {
                buildingRepository.deleteById(buildingDTO.getBuilding_id());
                //ADC sync for delete
                syncDeleteBuildingToADC(building_id);
                userActionLogService.addUserAction(username, "maps", "DELETE", "A Building with name : " + buildingDTO.getName() + " and id: " + building_id + " is deleted.", "success", "building", building_id);
                log.info("endpoint: {}, deleteBuildingById,  params: buildingDTO: {} ", endpoint, buildingDTO);
            } catch (Exception e) {
                userActionLogService.addUserAction(username, "maps", "DELETE", "Unable to delete building with name : " + buildingDTO.getName() + " and id: " + building_id, "failed", "building", building_id);
                log.error("Exception in Deleting Building By Id, endpoint: {}, Error message: ", endpoint, e);
            }
        }
    }

    public void syncDeleteBuildingToADC(String buildingId) {
        try {
            VdmsDTO vdmsDetails = vdmsRepository.getSyncDetailsForADC();
            List<String> buildingIds = Collections.singletonList(buildingId);
            Boolean status = apicallService.deleteBuildingFromADC(vdmsDetails.getCustomer_org_id(), vdmsDetails.getAdc_configuration_id(),  // make sure propertyId is correct
            buildingIds);
            log.info("Building DELETE synced to ADC successfully, Building ID: {}, Status: {}", buildingId, status);
        } catch (Exception e) {
            log.error("Exception while syncing deleted building to ADC, Building ID: {}", buildingId, e);
        }
    }

