    public Map<String, Object> syncLocationsFromBackend(HttpServletRequest httpServletRequest) {
        System.out.println("********************SYNC LOCATIONS FROM CLOUD************************************");
        //getting vdmsid of the sclera box
        String vdmsIdScleraBox = "VDMS400";
        // getting all buildings from location server..
        List<BuildingDTO> all_buildings = apiCallService.getAllLocations(vdmsIdScleraBox);
        log.info("\n***********************All Locations from CLOUD****************************\n{}", all_buildings);
        //Get all buildings from vdms server, before sync
        Set<BuildingDTO> vdms_buildings = this.getAllBuildingsBackendSync(vdmsIdScleraBox);
        log.info("\n***********************All Locations from VDMS BOX****************************\n{}", vdms_buildings);
        Set<String> building_ids = new HashSet<>();
        Set<String> floor_ids = new HashSet<>();
        Set<String> location_ids = new HashSet<>();
        for (BuildingDTO building : all_buildings) {
            building_ids.add(building.getBuilding_id());
            this.upsertBuildingById(building, vdmsIdScleraBox, "", "", httpServletRequest);
            //floor loop
            for (FloorDTO floor : building.getFloors()) {
                floor_ids.add(floor.getFloor_id());
                String image_url = floorservice.upsertFloorImageByBuildingFromBackend(floor);
                floor.setImage_url(image_url);
                floorservice.upsertFloorByBuildingIdsFromBackend(building.getBuilding_id(), floor);
                //Update floor path
                String path = apiCallService.getFloorPathByFloorId(null, vdmsIdScleraBox, building.getBuilding_id(), floor.getFloor_id());
                floorservice.updatePathByFloorId(null, floor.getFloor_id(), path, httpServletRequest);
                // for location
                for (LocationDTO location : floor.getLocations()) {
                    location_ids.add(location.getLocation_id());
                    // update  locations
                    locationService.upsertLocationByFloorIdBackendSync(floor.getFloor_id(), location);
                }
            }
        }
        if (vdms_buildings != null && vdms_buildings.size() > 0) {
            // delete building, floor and locations , which are deleted from server.
            return this.getMismatchedLocationsFromVdmsBackendSync(building_ids, floor_ids, location_ids, vdms_buildings, vdmsIdScleraBox);
        }
        return null;
    }

    private Map<String, Object> getMismatchedLocationsFromVdmsBackendSync(Set<String> building_ids, Set<String> floor_ids, Set<String> location_ids, Set<BuildingDTO> vdms_buildings, String vdms_id) {
        Map<String, Object> mismatched_locations = new HashMap();
        Set<Map<String, Object>> delete_buildings = new HashSet<>();
        Set<Map<String, Object>> delete_floors = new HashSet<>();
        Set<Map<String, Object>> delete_locations = new HashSet<>();
        Map<String, Object> location_object;
        for (BuildingDTO building : vdms_buildings) {
            if (compareIds(building_ids, building.getBuilding_id())) {
                if (building.getFloors() != null) {
                    for (FloorDTO floor : building.getFloors()) {
                        if (compareIds(floor_ids, floor.getFloor_id())) {
                            if (floor.getLocations() != null) {
                                for (LocationDTO location : floor.getLocations()) {
                                    if (!compareIds(location_ids, location.getLocation_id())) {
                                        location_object = new HashMap<>();
                                        location_object.put("building_id", building.getBuilding_id());
                                        location_object.put("building_name", building.getName());
                                        location_object.put("floor_id", floor.getFloor_id());
                                        location_object.put("floor_name", floor.getName());
                                        location_object.put("location_id", location.getLocation_id());
                                        location_object.put("location_name", location.getName());
                                        delete_locations.add(location_object);
                                    }
                                }
                            }
                        } else {
                            location_object = new HashMap<>();
                            location_object.put("building_id", building.getBuilding_id());
                            location_object.put("building_name", building.getName());
                            location_object.put("floor_id", floor.getFloor_id());
                            location_object.put("floor_name", floor.getName());
                            delete_floors.add(location_object);
                        }
                    }
                }
            } else {
                location_object = new HashMap<>();
                location_object.put("building_id", building.getBuilding_id());
                location_object.put("building_name", building.getName());
                delete_buildings.add(location_object);
            }
        }
        mismatched_locations.put("vdms_id", vdms_id);
        mismatched_locations.put("buildings", delete_buildings);
        mismatched_locations.put("floors", delete_floors);
        mismatched_locations.put("locations", delete_locations);
        return mismatched_locations;
    }

    private Set<BuildingDTO> getAllBuildingsBackendSync(String vdms_id) {
        Set<BuildingDTO> buildings = this.getBuildingsByVdmsId(vdms_id, null, null);
        for (BuildingDTO building : buildings) {
            Set<FloorDTO> floors = floorservice.getFloorsByBuildingId(null, null, building.getBuilding_id(), null, null);
            for (FloorDTO floor : floors) {
                floor.setLocations(locationService.getLocationsByFloorId(floor.getFloor_id(), vdms_id));
            }
            building.setFloors(floors);
        }
        return buildings;
    }

