    public Set<FloorDTO> syncFloorMaps(String vdms_id) {
        Set<BuildingDTO> buildings = this.getBuildingsByVdmsId(vdms_id, null, null);
        Set<FloorDTO> floors_response = new HashSet<>();
        for (BuildingDTO building : buildings) {
            Set<FloorDTO> floors = floorservice.getFloorsDetailsByBuildingId(building.getBuilding_id());
            for (FloorDTO floordto : floors) {
                FloorDTO floor = new FloorDTO();
                if (floordto.getImage_url() != null) {
                    floor.setFloor_id(floordto.getFloor_id());
                    floor.setImage_url(floordto.getImage_url());
                    if (floordto.getLocal_image_url() != null) {
                        floor.setLocal_image_url(floordto.getLocal_image_url());
                    } else {
                        floor.setLocal_image_url(floordto.getImage_url());
                    }
                    floors_response.add(floor);
                }
            }
        }
        return floors_response;
    }

