    //  syncFloorMapsTiles to be deleted after sync
    public List<FloorDTO> syncFloorMapsTiles() {
        String vdmsIdScleraBox = "VDMS400";
        Set<BuildingDTO> buildings = this.getBuildingsByVdmsId(vdmsIdScleraBox, null, null);
        List<FloorDTO> syncFailedFloors = new ArrayList<>();
        for (BuildingDTO building : buildings) {
            Set<FloorDTO> floors = floorservice.getFloorsDetailsByBuildingId(building.getBuilding_id());
            if (floors != null && floors.size() > 0) {
                for (FloorDTO floordto : floors) {
                    List<FloorDTO> floors_response = new ArrayList<>();
                    if (floordto.getImage_url() != null) {
                        FloorDTO floor = floorservice.mapInitialPositionToCoordinates(floordto.getInitial_position(), floordto.getFloor_id());
                        floor.setImage_url(floordto.getImage_url());
                        floors_response.add(floor);
                        syncFailedFloors.addAll(floorservice.syncFloorMapsTiles(vdmsIdScleraBox, floors_response));
                    }
                }
            }
        }
        return syncFailedFloors;
    }

